external_knowledge:
- "Voyagers" refers to the applicants;
- "Vessels" metaphorically represents the applications;
- "Points of origin" refer to the addresses;
- "Means by which we can hail them" are the contact details (email, phone number);
- "Navigating through the labyrinth of review" indicates that the applications are in the review status.

sql:
SELECT a.application_id, a.application_number, d.file_path
FROM applications a
JOIN application_documents d ON a.application_id = d.application_id;

SELECT AVG(estimated_cost) AS average_estimated_cost
FROM applications
WHERE application_type = 'MV';

SELECT application_id, status, created_by, updated_by
FROM applications
WHERE status = 'Under Review';

SELECT AVG(estimated_cost) AS average_estimated_cost
FROM applications
WHERE status = 'In Review';

SELECT SUM(estimated_cost) AS total_potential_harvest
FROM applications
WHERE status = 'Approved';

SELECT status, COUNT(*) as num_applications
FROM applications
GROUP BY status;

SELECT application_id, application_number, date_submitted, description, status, project_name, contact_email, contact_phone, estimated_cost, created_by, created_at
FROM applications
WHERE status = 'Under Review' AND application_type = 'MV';
